import React from 'react';
import Chat from './components/Chat';
import SafetyDisclaimer from './components/SafetyDisclaimer';

function App() {
  return (
    <div style={{padding:"20px"}}>
      <h1>AI Medical Assistant</h1>
      <SafetyDisclaimer />
      <Chat />
    </div>
  );
}

export default App;
